# NUCLEAR FIX: Move auth page to public/ so Vite copies it verbatim
# Run: Set-ExecutionPolicy Bypass -Scope Process -Force; .\NUCLEAR.ps1

$RepoPath = "C:\Users\LionelMosley\Documents\HTML\Synology - DiskStation Monitor"
Set-Location $RepoPath
Write-Host "Applying nuclear auth fix..." -ForegroundColor Cyan

# Write auth page to frontend/public/ so Vite copies it verbatim into dist/
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "frontend\public\dsm-auth.html"
$dir = Split-Path $fullPath -Parent
if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  wrote frontend/public/dsm-auth.html" -ForegroundColor Green

# Update netlify.toml CSP to allow inline scripts
$b64t = ""
$bytest = [System.Convert]::FromBase64String($b64t)
$tomlPath = Join-Path $RepoPath "netlify.toml"
[System.IO.File]::WriteAllBytes($tomlPath, $bytest)
Write-Host "  wrote netlify.toml (CSP updated)" -ForegroundColor Green

# Remove old auth page from frontend root so Vite doesn't override
$oldAuth = Join-Path $RepoPath "frontend\dsm-auth.html"
if (Test-Path $oldAuth) {
  Remove-Item $oldAuth
  Write-Host "  removed old frontend/dsm-auth.html" -ForegroundColor Yellow
}

git add -A
git commit -m "fix: move auth page to public/ for verbatim Vite copy, fix CSP for inline scripts"
git push origin main

if ($LASTEXITCODE -eq 0) {
    Write-Host "`n✅ Pushed! After Netlify rebuilds, try: https://dsm.4thandbailey.com/dsm-auth.html" -ForegroundColor Green
} else {
    Write-Host "`n❌ Push failed." -ForegroundColor Red
}